public static class Razred1 { 
   public int x = 4; 
   private int y = 2; 
   Razred1 () { 
      x -= 1; 
      y += 1; 
   } 
   Razred1 (int i) { 
      this(); 
      y += x++; 
      if (metoda()) System.out.print("x" + x + " y" + y); 
   } 
   private boolean metoda(){ 
       return (y%2==x%2); 
   } 
} 
